Create the hook that loads canvas state from localStorage when the session ID changes, and integrate it into the `SessionPage` widget.

## Files to create

### 1. `apps/client/src/layers/features/canvas/model/use-canvas-persistence.ts`

```typescript
import { useEffect } from 'react';
import { useAppStore } from '@/layers/shared/model';

/**
 * Hydrate canvas state from localStorage when the active session changes.
 *
 * Calls `loadCanvasForSession` on mount and whenever `sessionId` changes,
 * restoring the persisted open/closed state and content for that session.
 * When `sessionId` is undefined (no active session), this hook is a no-op.
 *
 * @param sessionId - The current session UUID from URL search params
 */
export function useCanvasPersistence(sessionId: string | undefined): void {
  const loadCanvasForSession = useAppStore((s) => s.loadCanvasForSession);

  useEffect(() => {
    if (sessionId) {
      loadCanvasForSession(sessionId);
    }
  }, [sessionId, loadCanvasForSession]);
}
```

## Files to modify

### 2. `apps/client/src/layers/widgets/session/ui/SessionPage.tsx`

Import and call `useCanvasPersistence` after the `useSessionId` call:

```typescript
import { Panel, PanelGroup } from 'react-resizable-panels';
import { ChatPanel } from '@/layers/features/chat';
import { AgentCanvas } from '@/layers/features/canvas';
import { useCanvasPersistence } from '@/layers/features/canvas';
import { useSessionId } from '@/layers/entities/session';

/**
 * Session route page — wraps ChatPanel with route-derived session ID.
 *
 * Renders a horizontal `PanelGroup` so that `AgentCanvas` can open as a
 * resizable right-hand panel alongside the chat. When the canvas is closed
 * it returns null and the chat panel expands to fill the full width.
 *
 * Canvas state (open/closed, content) is persisted per-session in localStorage
 * and hydrated on mount or session change via `useCanvasPersistence`.
 */
export function SessionPage() {
  const [activeSessionId] = useSessionId();
  useCanvasPersistence(activeSessionId);

  return (
    <PanelGroup direction="horizontal" autoSaveId={activeSessionId ? `agent-canvas-${activeSessionId}` : 'agent-canvas'}>
      <Panel id="chat" order={1} minSize={30} defaultSize={100}>
        <ChatPanel sessionId={activeSessionId} />
      </Panel>
      <AgentCanvas />
    </PanelGroup>
  );
}
```

### 3. Update canvas barrel export

Update `apps/client/src/layers/features/canvas/index.ts` to export the persistence hook (if not already done in task 2.2):

