## FSD compliance

- `useCanvasPersistence` lives in `features/canvas/model/` and imports only from `shared/model` — compliant
- `SessionPage` lives in `widgets/session/` and imports from `features/canvas` and `entities/session` — compliant (widgets can import from features and entities)

## Behavior

1. When `SessionPage` mounts, `useCanvasPersistence` fires with the current `activeSessionId`
2. `loadCanvasForSession(sessionId)` reads localStorage for that session's canvas state
3. If an entry exists: canvas opens with the stored content
4. If no entry exists: canvas starts closed with no content (clean default)
5. When `activeSessionId` changes (user navigates to a different session via URL or tab switch), the effect re-fires and loads the new session's canvas state
6. All subsequent `setCanvasOpen`/`setCanvasContent` calls write-through to localStorage (handled by task 1.3)

## Acceptance criteria

- On page refresh with a session that had canvas open, the canvas reopens with the same content
- On page refresh with a session that had canvas closed, the canvas stays closed
- Switching from session A (canvas open) to session B (canvas closed) correctly closes the canvas
- Switching from session B back to session A correctly reopens the canvas with the original content
- A brand new session (no localStorage entry) starts with canvas closed and no content
- When `activeSessionId` is `undefined`, the hook does nothing
- TypeScript compiles without errors

Add unit tests for the canvas session localStorage helpers, covering normal operations, LRU eviction, and error handling.

## File to create

`apps/client/src/layers/shared/model/__tests__/canvas-session-helpers.test.ts`

## Test implementation

```typescript
import { describe, it, expect, beforeEach, vi } from 'vitest';
import { readCanvasSession, writeCanvasSession } from '../app-store-helpers';
import { STORAGE_KEYS, MAX_CANVAS_SESSIONS } from '@/layers/shared/lib';
import type { CanvasSessionEntry } from '../app-store-helpers';

describe('readCanvasSession', () => {
  beforeEach(() => {
    localStorage.clear();
  });

  it('returns null when no data exists in localStorage', () => {
    expect(readCanvasSession('session-1')).toBeNull();
  });

  it('returns null when session ID is not in the map', () => {
    const map = { 'other-session': { open: true, content: null, accessedAt: 1000 } };
    localStorage.setItem(STORAGE_KEYS.CANVAS_SESSIONS, JSON.stringify(map));
    expect(readCanvasSession('session-1')).toBeNull();
  });

  it('returns the entry when session ID exists', () => {
    const entry: CanvasSessionEntry = { open: true, content: null, accessedAt: 1000 };
    const map = { 'session-1': entry };
    localStorage.setItem(STORAGE_KEYS.CANVAS_SESSIONS, JSON.stringify(map));

    const result = readCanvasSession('session-1');
    expect(result).toEqual(entry);
  });

  it('returns entry with content when content is stored', () => {
    const entry: CanvasSessionEntry = {
      open: true,
      content: { type: 'markdown', content: '# Hello', title: 'Test' },
      accessedAt: 1000,
    };
    const map = { 'session-1': entry };
    localStorage.setItem(STORAGE_KEYS.CANVAS_SESSIONS, JSON.stringify(map));

    const result = readCanvasSession('session-1');
    expect(result).toEqual(entry);
    expect(result?.content?.type).toBe('markdown');
  });

  it('returns null when localStorage contains corrupt JSON', () => {
    localStorage.setItem(STORAGE_KEYS.CANVAS_SESSIONS, 'not-valid-json{{{');
    expect(readCanvasSession('session-1')).toBeNull();
  });

  it('returns null when localStorage throws (e.g., SecurityError)', () => {
    vi.spyOn(Storage.prototype, 'getItem').mockImplementation(() => {
      throw new DOMException('blocked', 'SecurityError');
    });
    expect(readCanvasSession('session-1')).toBeNull();
    vi.restoreAllMocks();
  });
});

describe('writeCanvasSession', () => {
  beforeEach(() => {
    localStorage.clear();
  });

  it('writes a new entry to localStorage', () => {
    const entry: CanvasSessionEntry = { open: true, content: null, accessedAt: 0 };
    writeCanvasSession('session-1', entry);

    const stored = JSON.parse(localStorage.getItem(STORAGE_KEYS.CANVAS_SESSIONS)!);
    expect(stored['session-1']).toBeDefined();
    expect(stored['session-1'].open).toBe(true);
    // accessedAt should be updated to a recent timestamp
    expect(stored['session-1'].accessedAt).toBeGreaterThan(0);
  });

  it('updates an existing entry', () => {
    writeCanvasSession('session-1', { open: true, content: null, accessedAt: 0 });
    writeCanvasSession('session-1', { open: false, content: null, accessedAt: 0 });

    const stored = JSON.parse(localStorage.getItem(STORAGE_KEYS.CANVAS_SESSIONS)!);
    expect(stored['session-1'].open).toBe(false);
  });

  it('preserves other sessions when writing', () => {
    writeCanvasSession('session-1', { open: true, content: null, accessedAt: 0 });
    writeCanvasSession('session-2', { open: false, content: null, accessedAt: 0 });

    const stored = JSON.parse(localStorage.getItem(STORAGE_KEYS.CANVAS_SESSIONS)!);
    expect(stored['session-1']).toBeDefined();
    expect(stored['session-2']).toBeDefined();
  });

  it('evicts oldest entries when exceeding MAX_CANVAS_SESSIONS', () => {
    // Write MAX_CANVAS_SESSIONS entries with known timestamps
    for (let i = 0; i < MAX_CANVAS_SESSIONS; i++) {
      const map = JSON.parse(localStorage.getItem(STORAGE_KEYS.CANVAS_SESSIONS) || '{}');
      map[`session-${i}`] = { open: false, content: null, accessedAt: i };
      localStorage.setItem(STORAGE_KEYS.CANVAS_SESSIONS, JSON.stringify(map));
    }

    // Write one more — should evict session-0 (oldest accessedAt = 0)
    writeCanvasSession('session-new', { open: true, content: null, accessedAt: 0 });

    const stored = JSON.parse(localStorage.getItem(STORAGE_KEYS.CANVAS_SESSIONS)!);
    const keys = Object.keys(stored);
    expect(keys.length).toBe(MAX_CANVAS_SESSIONS);
    expect(stored['session-0']).toBeUndefined(); // evicted
    expect(stored['session-new']).toBeDefined(); // newest
  });

  it('does not throw when localStorage is full (quota exceeded)', () => {
    vi.spyOn(Storage.prototype, 'setItem').mockImplementation(() => {
